50.         }
51. 
52.         // Anti-pattern: Dictionary allocated on EVERY call — ~10 allocations per invocation
53.         // (dictionary + buckets + entries + 6 Func closures capturing 'this')
54.         // Should be hoisted to a static readonly field
55.         var farsiGroupsMap = new Dictionary<long, Func<long, string>>
56.         {
57.             { (long)Math.Pow(10, 15), n => $"{Convert(n)} کوادریلیون" },
58.             { (long)Math.Pow(10, 12), n => $"{Convert(n)} تریلیون" },
59.             { (long)Math.Pow(10, 9), n => $"{Convert(n)} میلیارد" },
