         var groupKeys = new long[] { (long)Math.Pow(10, 15), (long)Math.Pow(10, 12), (long)Math.Pow(10, 9), (long)Math.Pow(10, 6), (long)Math.Pow(10, 3), (long)Math.Pow(10, 2) };

